import React, { useEffect, useState } from 'react';
import axios from 'axios';
import Slider from 'react-slick';
import 'slick-carousel/slick/slick.css';
import 'slick-carousel/slick/slick-theme.css';
import '../Styles/Global.css';

const Home = () => {
  const [featuredPlants, setFeaturedPlants] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [featuredRes, categoriesRes] = await Promise.all([
          axios.get('http://localhost:5000/api/admin/products/featured'),
          axios.get('http://localhost:5000/api/admin/products/categories')
        ]);
        setFeaturedPlants(featuredRes.data);
        setCategories(categoriesRes.data);
        setLoading(false);
      } catch (error) {
        console.error('Failed to fetch data', error);
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const carouselSettings = {
    dots: true,
    infinite: true,
    speed: 500,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 5000,
    arrows: false,
    fade: true
  };

  const carouselImages = [
    {
      id: 1,
      src: '/assets/carousel1.jpg',
      alt: 'Beautiful indoor plants',
      title: 'Bring Nature Indoors',
      subtitle: 'Discover our collection of air-purifying plants'
    },
    {
      id: 2,
      src: '/assets/carousel2.jpg',
      alt: 'Plant care tools',
      title: 'Everything for Plant Care',
      subtitle: 'Find all the tools you need for healthy plants'
    },
    {
      id: 3,
      src: '/assets/carousel3.jpg',
      alt: 'Garden plants',
      title: 'Transform Your Garden',
      subtitle: 'Premium outdoor plants for every season'
    }
  ];

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loading-spinner"></div>
        <p>Loading...</p>
      </div>
    );
  }

  return (
    <div className="main-container">
      {/* Hero Carousel */}
      <section className="hero-carousel">
        <Slider {...carouselSettings}>
          {carouselImages.map((slide) => (
            <div key={slide.id} className="carousel-slide">
              <div className="carousel-image-container">
                <img 
                  src={slide.src} 
                  alt={slide.alt} 
                  className="carousel-image"
                />
              </div>
              <div className="carousel-content">
                <h1>{slide.title}</h1>
                <p>{slide.subtitle}</p>
                <a href="/catalog" className="carousel-button">
                  Shop Now
                </a>
              </div>
            </div>
          ))}
        </Slider>
      </section>

      {/* Categories */}
      <section className="category-section">
        <div className="section-header">
          <h2>Shop by Category</h2>
          <p>Find the perfect plants for your space</p>
        </div>
        <div className="category-cards">
          {Array.isArray(categories) && categories
            .filter(cat => cat && typeof cat.name === 'string')
            .map((cat, i) => (
              <a
                key={i}
                href={`/catalog?category=${cat.name.toLowerCase()}`}
                className="category-card"
              >
                <div className="category-image-container">
                  <img
                    src={`http://localhost:5000/Uploads/${cat.imageUrl || 'placeholder.jpg'}`}
                    alt={cat.name}
                    className="category-image"
                  />
                </div>
                <h3>{cat.name}</h3>
              </a>
            ))}
        </div>
      </section>

      {/* Featured Products */}
      <section className="featured-section">
        <div className="section-header">
          <h2>Featured Plants</h2>
          <p>Our most popular plants this season</p>
        </div>
        <div className="plant-grid">
          {featuredPlants.map((plant) => (
            <div className="plant-card" key={plant._id}>
              <div className="plant-image-container">
                <img 
                  src={`http://localhost:5000/uploads/${plant.imageUrl}`} 
                  alt={plant.name} 
                  className="plant-image"
                />
                {plant.stock <= 0 && (
                  <div className="out-of-stock-label">Out of Stock</div>
                )}
              </div>
              <div className="plant-info">
                <h3>{plant.name}</h3>
                <p className="plant-price">${plant.price.toFixed(2)}</p>
                <a href={`/product/${plant._id}`} className="view-details-button">
                  View Details
                </a>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* About Section */}
      <section className="about-section">
        <div className="about-content">
          <div className="about-text">
            <h2>About NatureNest</h2>
            <p>
              We're passionate about bringing nature into your home and life. 
              Our nursery specializes in healthy, vibrant plants that thrive in 
              any environment.
            </p>
            <a href="/about" className="learn-more-button">
              Learn More
            </a>
          </div>
          <div className="about-image">
            <img src="/assets/about-image.jpg" alt="Our nursery" />
          </div>
        </div>
      </section>
    </div>
  );
};

export default Home;
